// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function problemsPath(): string {
  return path.join(tmpDir, '.claude', 'memory', 'open-problems.jsonl');
}

function solutionsPath(): string {
  return path.join(tmpDir, '.claude', 'memory', 'problem-solutions.jsonl');
}

function writeProblem(p: Partial<Problem> & { id: string }): void {
  const full: Problem = {
    text: 'some problem',
    timestamp: new Date().toISOString(),
    session_id: 'sess-1',
    status: 'open',
    entities: [],
    project: 'test',
    ...p,
  };
  fs.appendFileSync(problemsPath(), JSON.stringify(full) + '\n');
}

