// ===========================================================================
// Confidence calculation
// ===========================================================================

describe('calculateSolutionConfidence', () => {
  const baseProblem: Problem = {
    id: 'p1',
    text: 'tests are failing',
    timestamp: new Date().toISOString(),
    session_id: 'sess-1',
    status: 'open',
    entities: ['vitest'],
    project: 'test',
  };

  it('starts at base confidence of 0.3', () => {
    const c = calculateSolutionConfidence(baseProblem, 'some output', 'Read');
    expect(c).toBeCloseTo(0.3, 1);
  });

  it('boosts for exit code 0', () => {
    const c = calculateSolutionConfidence(baseProblem, 'some output', 'Bash', 0);
    expect(c).toBeGreaterThan(0.3);
  });

  it('reduces for non-zero exit code', () => {
    const c = calculateSolutionConfidence(baseProblem, 'some output', 'Bash', 1);
    expect(c).toBeLessThan(0.3);
  });

  it('boosts for success patterns in output', () => {
    const c = calculateSolutionConfidence(baseProblem, 'All tests passed', 'Bash', 0);
    expect(c).toBeGreaterThan(0.5);
  });

  it('reduces for failure patterns in output', () => {
    const c = calculateSolutionConfidence(baseProblem, 'error: test failed', 'Bash', 1);
    expect(c).toBeLessThan(0.1);
  });

  it('boosts for entity overlap', () => {
    const withEntities = calculateSolutionConfidence(
      baseProblem,
      'vitest run completed',
      'Bash',
      0
    );
    const withoutEntities = calculateSolutionConfidence(
      { ...baseProblem, entities: [] },
      'vitest run completed',
      'Bash',
      0
    );
    expect(withEntities).toBeGreaterThan(withoutEntities);
  });

  it('boosts Bash tool with test keywords', () => {
    const withTest = calculateSolutionConfidence(baseProblem, 'pytest output', 'Bash');
    const withoutTest = calculateSolutionConfidence(baseProblem, 'some output', 'Bash');
    expect(withTest).toBeGreaterThan(withoutTest);
  });

  it('slightly boosts Write/Edit tools', () => {
    const write = calculateSolutionConfidence(baseProblem, 'some output', 'Write');
    const read = calculateSolutionConfidence(baseProblem, 'some output', 'Read');
    expect(write).toBeGreaterThan(read);
  });

  it('clamps confidence between 0 and 1', () => {
    // Many failure patterns to drive confidence very low
    const lowOutput = 'error failed exception crash timeout undefined syntax error type error cannot find';
    const c = calculateSolutionConfidence(baseProblem, lowOutput, 'Bash', 1);
    expect(c).toBeGreaterThanOrEqual(0);
    expect(c).toBeLessThanOrEqual(1);
  });
});

