describe('summarizeSolution', () => {
  it('extracts context around a success pattern match', () => {
    const output = 'Running vitest... All tests passed in 2.3s';
    const summary = summarizeSolution(output, 'Bash');
    expect(summary.length).toBeGreaterThan(0);
    expect(summary.length).toBeLessThanOrEqual(200);
  });

  it('falls back to first meaningful line', () => {
    const output = '\n\nThis is a normal output line for the tool\n';
    const summary = summarizeSolution(output, 'Bash');
    expect(summary).toBe('This is a normal output line for the tool');
  });

  it('produces generic summary with file name', () => {
    const output = '';
    const summary = summarizeSolution(output, 'Write', '/src/app.ts');
    expect(summary).toBe('Write operation on app.ts completed');
  });

  it('produces generic summary without file', () => {
    const output = '';
    const summary = summarizeSolution(output, 'Edit');
    expect(summary).toBe('Edit completed successfully');
  });
});

// ===========================================================================
// loadOpenProblems
