describe('loadOpenProblems', () => {
  it('returns empty array when file does not exist', () => {
    expect(loadOpenProblems()).toEqual([]);
  });

  it('loads open problems from JSONL', () => {
    writeProblem({ id: 'p1', status: 'open' });
    writeProblem({ id: 'p2', status: 'solved' });
    writeProblem({ id: 'p3', status: 'open' });

    const problems = loadOpenProblems();
    expect(problems).toHaveLength(2);
    expect(problems.map(p => p.id)).toContain('p1');
    expect(problems.map(p => p.id)).toContain('p3');
  });

  it('filters by session ID when provided', () => {
    writeProblem({ id: 'p1', session_id: 'sess-a' });
    writeProblem({ id: 'p2', session_id: 'sess-b' });

    const problems = loadOpenProblems('sess-a');
    expect(problems).toHaveLength(1);
    expect(problems[0].id).toBe('p1');
  });

  it('skips malformed JSONL lines', () => {
    fs.appendFileSync(problemsPath(), 'not json\n');
    writeProblem({ id: 'p1' });

    const problems = loadOpenProblems();
    expect(problems).toHaveLength(1);
  });

  it('returns most recent first, limited to 50', () => {
    for (let i = 0; i < 55; i++) {
      writeProblem({ id: `p${i}` });
    }
    const problems = loadOpenProblems();
    expect(problems.length).toBeLessThanOrEqual(50);
    // Most recent should be first (reversed)
    expect(problems[0].id).toBe('p54');
  });
});

// ===========================================================================
// updateProblemStatus
