describe('updateProblemStatus', () => {
  it('returns false when file does not exist', () => {
    expect(updateProblemStatus('p1', 'solved')).toBe(false);
  });

  it('marks a problem as solved with solution', () => {
    writeProblem({ id: 'p1' });

    const solution = {
      text: 'fixed it',
      tool: 'Edit',
      timestamp: new Date().toISOString(),
      confidence: 0.8,
    };

    expect(updateProblemStatus('p1', 'solved', solution)).toBe(true);

    const content = fs.readFileSync(problemsPath(), 'utf-8');
    const parsed = JSON.parse(content.trim());
    expect(parsed.status).toBe('solved');
    expect(parsed.solution.text).toBe('fixed it');
  });

  it('marks a problem as abandoned', () => {
    writeProblem({ id: 'p1' });
    expect(updateProblemStatus('p1', 'abandoned')).toBe(true);

    const content = fs.readFileSync(problemsPath(), 'utf-8');
    const parsed = JSON.parse(content.trim());
    expect(parsed.status).toBe('abandoned');
  });

  it('returns false for non-existent problem ID', () => {
    writeProblem({ id: 'p1' });
    expect(updateProblemStatus('p999', 'solved')).toBe(false);
  });

  it('handles malformed lines gracefully', () => {
    fs.appendFileSync(problemsPath(), 'not json\n');
    writeProblem({ id: 'p1' });

    expect(updateProblemStatus('p1', 'solved')).toBe(true);
  });
});

