describe('pairSolutionWithProblems', () => {
  it('returns 0 when output is pure failure', () => {
    writeProblem({ id: 'p1' });
    const count = pairSolutionWithProblems('error: test failed', 'Bash', undefined, 1, 'sess-1');
    expect(count).toBe(0);
  });

  it('returns 0 when no open problems', () => {
    const count = pairSolutionWithProblems('all tests passed', 'Bash', undefined, 0, 'sess-1');
    expect(count).toBe(0);
  });

  it('pairs high-confidence solutions with problems', () => {
    writeProblem({ id: 'p1', session_id: 'sess-1', entities: ['vitest'] });

    const count = pairSolutionWithProblems(
      'All tests passed! vitest completed successfully',
      'Bash',
      undefined,
      0,
      'sess-1'
    );

    expect(count).toBeGreaterThanOrEqual(1);

    // Verify the solution file was created
    expect(fs.existsSync(solutionsPath())).toBe(true);
  });

  it('skips pairing when confidence is below threshold', () => {
    // Problem with no entity overlap, neutral output, non-zero exit
    writeProblem({ id: 'p1', session_id: 'sess-1', entities: ['react'] });

    const count = pairSolutionWithProblems(
      'some neutral output',
      'Read',
      undefined,
      undefined,
      'sess-1'
    );

    expect(count).toBe(0);
  });
});

// ===========================================================================
// abandonStaleProblems
// ===========================================================================

describe('abandonStaleProblems', () => {
  it('returns 0 when no problems exist', () => {
    expect(abandonStaleProblems()).toBe(0);
  });

  it('abandons problems older than threshold', () => {
    const oldTimestamp = new Date(Date.now() - 48 * 60 * 60 * 1000).toISOString();
    writeProblem({ id: 'p-old', timestamp: oldTimestamp });
    writeProblem({ id: 'p-new', timestamp: new Date().toISOString() });

    const abandoned = abandonStaleProblems(24 * 60 * 60 * 1000);
    expect(abandoned).toBe(1);
  });

  it('uses default 24h threshold', () => {
    const oldTimestamp = new Date(Date.now() - 25 * 60 * 60 * 1000).toISOString();
    writeProblem({ id: 'p-old', timestamp: oldTimestamp });

    const abandoned = abandonStaleProblems();
    expect(abandoned).toBe(1);
  });

  it('does not abandon recent problems', () => {
    writeProblem({ id: 'p-new', timestamp: new Date().toISOString() });
    const abandoned = abandonStaleProblems();
    expect(abandoned).toBe(0);
  });
});

